parameters.text:
=You are an expert HR data parser. Analyze the provided job description and candidate resume to extract data according to the schema.

JOB DESCRIPTION:
{{ $('HTTP Request').item.json.data }}

CANDIDATE RESUME:
{{ $('Extract from File').item.json.text }}

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "company_name": {
      "type": "string",
      "description": "The name of the company hiring for this position (extracted from the job description)"
    },
    "job_title": {
      "type": "string",
      "description": "The official title of the job position (extracted from the job description)"
    },
    "name": {
      "type": "string",
      "description": "Candidate's full name"
    },
    "email": {
      "type": "string",
      "description": "Candidate's email address"
    },
    "top_skills": {
      "type": "string",
      "description": "Comma-separated list of top 3 skills matching this specific role"
    },
    "match_score": {
      "type": "number",
      "description": "A score out of 100 on how well the candidate fits this specific role"
    },
    "superpower": {
      "type": "string",
      "description": "One short sentence describing why the candidate is a unique fit for this specific company"
    }
  },
  "required": ["company_name", "job_title", "name", "email", "top_skills", "match_score", "superpower"]
}

parameters.jsCode:
for (const item of $input.all()) {
  // n8n AI Agent nodes output their text result inside the 'output' key
  const emailText = item.json.output; 

  // Wraps the generated letter in a clean, modern email shell without the header
  const htmlBody = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; line-height: 1.6; color: #1a1a1a; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; padding: 24px; border-radius: 12px; background-color: #ffffff;">
  <p style="font-size: 15px; white-space: pre-line; color: #334155; margin-top: 0;">${emailText}</p>
  <br />
  <div style="background-color: #f8fafc; padding: 16px; border-left: 4px solid #FF6C37; border-radius: 6px; font-size: 13px; color: #475569;">
    <strong>⚡ Workflow Automation Note:</strong> This letter was dynamically generated by an n8n workflow. The pipeline automatically scraped the target job description via Jina AI, extracted core skills using Gemini, logged tracking data into Google Sheets, and rendered this HTML format.
  </div>
</div>
  `;

  // Inject the new HTML layout into the JSON stream
  item.json.htmlBody = htmlBody;
}

return $input.all();
